const pyScript = `
import json, os, sys
from openpyxl import Workbook, load_workbook
from openpyxl.styles import Font, PatternFill, Alignment, Border, Side
from openpyxl.utils import get_column_letter

FILES_PATH = '/home/node/n8n-local-files'
EXCEL_PATH = os.path.join(FILES_PATH, 'unit_tests.xlsx')
SHEET_NAME = 'Unit Test Cases'

HEADERS = [
    'Feature ID', 'Feature Description', 'TC written by',
    'TS ID', 'TS Description', 'TC ID', 'TC Description',
    'Test Steps', 'Test Data', 'Expected Result',
    'Actual Result', 'Status', 'Severity', 'Comments', 'Version'
]

COL_WIDTHS = [12, 35, 15, 10, 35, 10, 35, 50, 20, 35, 20, 12, 12, 20, 10]

thin = Side(style='thin', color='000000')
border = Border(left=thin, right=thin, top=thin, bottom=thin)
center = Alignment(horizontal='center', vertical='center', wrap_text=True)
left_wrap = Alignment(horizontal='left', vertical='center', wrap_text=True)

def style_header_row(ws):
    header_fill = PatternFill('solid', start_color='1F4E79', end_color='1F4E79')
    header_font = Font(bold=True, color='FFFFFF', name='Arial', size=10)
    for col in range(1, len(HEADERS) + 1):
        cell = ws.cell(row=1, column=col)
        cell.font = header_font
        cell.fill = header_fill
        cell.alignment = center
        cell.border = border
    ws.row_dimensions[1].height = 30
    for i, w in enumerate(COL_WIDTHS, 1):
        ws.column_dimensions[get_column_letter(i)].width = w
    ws.freeze_panes = 'A2'

def style_data_row(ws, row_num, alt=False):
    fill_color = 'D6E4F0' if alt else 'FFFFFF'
    fill = PatternFill('solid', start_color=fill_color, end_color=fill_color)
    for col in range(1, len(HEADERS) + 1):
        cell = ws.cell(row=row_num, column=col)
        cell.font = Font(name='Arial', size=10)
        cell.fill = fill
        cell.alignment = left_wrap
        cell.border = border
    ws.row_dimensions[row_num].height = 60

if os.path.exists(EXCEL_PATH):
    try:
        wb = load_workbook(EXCEL_PATH)
        ws = wb[SHEET_NAME] if SHEET_NAME in wb.sheetnames else wb.active
    except Exception:
        wb = Workbook(); ws = wb.active; ws.title = SHEET_NAME
else:
    wb = Workbook()
    ws = wb.active
    ws.title = SHEET_NAME
    for col, h in enumerate(HEADERS, 1):
        ws.cell(row=1, column=col, value=h)
    style_header_row(ws)

def get_last_row(ws):
    for row in range(ws.max_row, 0, -1):
        if any(ws.cell(row=row, column=col).value for col in range(1, ws.max_column + 1)):
            return row
    return 0

next_row = get_last_row(ws) + 1
feature_id = ${JSON.stringify(feature_id)}
feature_description = ${JSON.stringify(feature_description)}
written_by = ${JSON.stringify(written_by)}
version = ${JSON.stringify(version)}
test_cases = ${JSON.stringify(test_cases)}

for i, tc in enumerate(test_cases):
    alt = (next_row % 2 == 0)
    row = [
        feature_id, feature_description, written_by,
        tc.get('ts_id', ''), tc.get('ts_description', ''),
        tc.get('tc_id', ''), tc.get('tc_description', ''),
        tc.get('test_steps', ''), tc.get('test_data', ''),
        tc.get('expected_result', ''), '', '',
        tc.get('severity', ''), '', version
    ]
    for col, val in enumerate(row, 1):
        ws.cell(row=next_row, column=col, value=val)
    style_data_row(ws, next_row, alt=alt)
    next_row += 1

wb.save(EXCEL_PATH)
print(json.dumps({'status': 'success', 'rows_added': len(test_cases), 'file': EXCEL_PATH}))
`;

const pyPath = filesPath + '/write_test_cases.py';
